"use client";

import { Wallet, Plus, TrendingUp, TrendingDown, DollarSign, CreditCard } from "lucide-react";
import { motion } from "framer-motion";
import { useState } from "react";
import { Area, AreaChart, ResponsiveContainer, Tooltip, XAxis } from "recharts";

const data = [
    { name: "S1", val: 400 },
    { name: "S2", val: 300 },
    { name: "S3", val: 550 },
    { name: "S4", val: 480 },
];

export default function IncomePage() {
    const [activeTab, setActiveTab] = useState("overview");

    return (
        <motion.div
            initial={{ opacity: 0, scale: 0.98 }}
            animate={{ opacity: 1, scale: 1 }}
            transition={{ duration: 0.4 }}
            className="space-y-8"
        >
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h2 className="text-3xl font-bold tracking-tight text-foreground flex items-center gap-2">
                        <span className="bg-emerald-100 text-emerald-600 p-2 rounded-lg dark:bg-emerald-900/30">
                            <TrendingUp className="h-6 w-6" />
                        </span>
                        Ingresos
                    </h2>
                    <p className="text-muted-foreground mt-1">Control de cuotas, lotería y subvenciones.</p>
                </div>
                <div className="flex gap-2">
                    <button className="inline-flex items-center justify-center rounded-xl text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring border border-input bg-background hover:bg-accent hover:text-accent-foreground h-10 px-4 py-2">
                        Exportar
                    </button>
                    <button className="inline-flex items-center justify-center rounded-xl text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring bg-emerald-600 text-white hover:bg-emerald-700 h-10 px-4 py-2 shadow-sm hover:shadow-emerald-500/20">
                        <Plus className="mr-2 h-4 w-4" />
                        Registrar Ingreso
                    </button>
                </div>
            </div>

            <div className="grid gap-6 md:grid-cols-3">
                <MetricCard
                    title="Total Recaudado"
                    value="45.230 €"
                    trend="+12%"
                    trendUp={true}
                    icon={DollarSign}
                    color="emerald"
                />
                <MetricCard
                    title="Cuotas Pendientes"
                    value="3.200 €"
                    trend="45 recibos"
                    trendUp={false}
                    icon={CreditCard}
                    color="amber"
                    alert
                />
                <MetricCard
                    title="Beneficio Lotería"
                    value="2.150 €"
                    trend="Campaña actual"
                    trendUp={true}
                    icon={Wallet}
                    color="blue"
                />
            </div>

            <div className="bg-card rounded-2xl border border-border/50 shadow-sm overflow-hidden">
                <div className="flex border-b border-border/50">
                    {["Resumen", "Cuotas", "Lotería", "Subvenciones"].map((tab) => (
                        <button
                            key={tab}
                            onClick={() => setActiveTab(tab.toLowerCase())}
                            className={`px-6 py-4 text-sm font-medium border-b-2 transition-colors ${activeTab === tab.toLowerCase()
                                    ? "border-primary text-primary bg-primary/5"
                                    : "border-transparent text-muted-foreground hover:text-foreground hover:bg-muted/30"
                                }`}
                        >
                            {tab}
                        </button>
                    ))}
                </div>

                <div className="p-6">
                    <h3 className="text-lg font-medium leading-6 mb-6 flex items-center justify-between">
                        <span>Últimos Movimientos</span>
                        <span className="text-xs font-normal text-muted-foreground bg-muted px-2 py-1 rounded-md">Últimos 30 días</span>
                    </h3>

                    <div className="space-y-4">
                        {[
                            { date: "09 Feb", desc: "Cuota Trimestral - Juan Pérez", cat: "Cuota", amount: "+60,00 €" },
                            { date: "08 Feb", desc: "Venta Papeletas Navidad", cat: "Lotería", amount: "+1.200,00 €" },
                            { date: "05 Feb", desc: "Subvención Fiestas 2024", cat: "Subvención", amount: "+3.000,00 €" },
                            { date: "02 Feb", desc: "Patrocinio Bar El Rincón", cat: "Patrocinio", amount: "+500,00 €" },
                        ].map((t, i) => (
                            <motion.div
                                initial={{ opacity: 0, x: -10 }}
                                animate={{ opacity: 1, x: 0 }}
                                transition={{ delay: i * 0.1 }}
                                key={i}
                                className="flex items-center justify-between p-4 rounded-xl border border-border/40 hover:bg-muted/30 transition-colors group cursor-pointer"
                            >
                                <div className="flex items-center gap-4">
                                    <div className="h-12 w-12 rounded-full bg-emerald-50 text-emerald-600 flex items-center justify-center group-hover:scale-110 transition-transform dark:bg-emerald-900/20">
                                        <TrendingUp className="h-5 w-5" />
                                    </div>
                                    <div>
                                        <p className="font-semibold text-foreground">{t.desc}</p>
                                        <div className="flex items-center gap-2 text-xs text-muted-foreground mt-0.5">
                                            <span>{t.date}</span>
                                            <span className="w-1 h-1 rounded-full bg-muted-foreground/50" />
                                            <span className="bg-muted px-1.5 rounded text-[10px] uppercase tracking-wide">{t.cat}</span>
                                        </div>
                                    </div>
                                </div>
                                <div className="text-right">
                                    <p className="font-bold text-emerald-600 dark:text-emerald-500 text-lg">{t.amount}</p>
                                    <p className="text-xs text-muted-foreground">Completado</p>
                                </div>
                            </motion.div>
                        ))}
                    </div>
                </div>
            </div>
        </motion.div>
    );
}

function MetricCard({ title, value, trend, trendUp, icon: Icon, color, alert }: any) {
    const colorClasses: Record<string, string> = {
        emerald: "bg-emerald-50 text-emerald-600 dark:bg-emerald-900/20 dark:text-emerald-400",
        amber: "bg-amber-50 text-amber-600 dark:bg-amber-900/20 dark:text-amber-400",
        blue: "bg-blue-50 text-blue-600 dark:bg-blue-900/20 dark:text-blue-400",
    };

    return (
        <div className="rounded-2xl border bg-card text-card-foreground shadow-sm p-6 relative overflow-hidden group">
            <div className={`absolute top-0 right-0 p-4 opacity-20 group-hover:opacity-40 transition-opacity`}>
                <Icon className="h-24 w-24 -mr-4 -mt-4 rotate-12" />
            </div>
            <div className="relative z-10">
                <div className="flex items-center justify-between mb-4">
                    <h3 className="text-sm font-medium text-muted-foreground">{title}</h3>
                    <div className={`p-2 rounded-lg ${colorClasses[color]}`}>
                        <Icon className="h-4 w-4" />
                    </div>
                </div>
                <div className="flex items-baseline gap-2">
                    <span className="text-3xl font-bold tracking-tight">{value}</span>
                </div>
                <div className="mt-2 flex items-center text-xs">
                    <span className={`font-medium px-1.5 py-0.5 rounded ${alert ? "bg-red-100 text-red-700" : "bg-emerald-100 text-emerald-700"}`}>
                        {trend}
                    </span>
                    <span className="text-muted-foreground ml-2">
                        {alert ? "requiere atención" : "vs mes anterior"}
                    </span>
                </div>
            </div>
            <div className="absolute bottom-0 left-0 right-0 h-1 bg-gradient-to-r from-transparent via-primary/20 to-transparent opacity-0 group-hover:opacity-100 transition-opacity" />
        </div>
    )
}
